private function normalize_table_data_version($value){
    $value = (int)$value;
    if($value <= 0)
    {
        return 0;
    }
    if($value < 100000000000 && $value > 1000000000)
    {
        return $value * 1000;
    }
    return $value;
}
private function get_table_data_version($data = array()){
    if(!is_array($data) || empty($data))
    {
        return 0;
    }
    return max(
        $this->normalize_table_data_version(isset($data['ver']) ? $data['ver'] : 0),
        $this->normalize_table_data_version(isset($data['online_ver']) ? $data['online_ver'] : 0),
        $this->normalize_table_data_version(isset($data['system_ver']) ? $data['system_ver'] : 0),
        $this->normalize_table_data_version(isset($data['created_at_time']) ? $data['created_at_time'] : 0)
    );
}
private function normalize_table_data_versions($data = array()){
    if(!is_array($data) || empty($data))
    {
        return $data;
    }
    $version = $this->get_table_data_version($data);
    if($version > 0)
    {
        $data['ver'] = max($this->normalize_table_data_version(isset($data['ver']) ? $data['ver'] : 0),$version);
        $data['online_ver'] = max($this->normalize_table_data_version(isset($data['online_ver']) ? $data['online_ver'] : 0),$version);
        $data['system_ver'] = $version;
    }
    return $data;
}
private function clear_table_runtime_cache($table_id,$type = 'dine_in',$outlet_id = 0){
    $table_key = $table_id;
    if($type != 'dine_in')
    {
        $table_key = $type.'-'.$table_id;
    }
    $cache_group = $this->_cache_group;
    $cache_keys = array(
        'op_table_'.$outlet_id.'_'.$table_key,
        'op_table_0_'.$table_key,
    );
    foreach(array_unique($cache_keys) as $cache_key)
    {
        wp_cache_delete($cache_key, $cache_group );
    }
    if($type == 'dine_in')
    {
        wp_cache_delete('op_table_'.$table_id, $cache_group );
        if($outlet_id >= 0)
        {
            wp_cache_delete('op_tables_'.$outlet_id, $cache_group );
        }
    }
}
